pair A=(5,2), B=(-3,8), C=(-3,-4);

pair[] dots={A,B,C};

dot(dots);

label("(5,2)",A,E);

draw((-3,-6)--(-3,10),linetype("3 3"),Arrows(4));

draw(B--A--C);

label("10",(A+B)/2,NE);

label("10",(A+C)/2,SE);

label("$x=-3$",(-3,-6),S);[/asy]

